    n: int,
    byzantine_count: int,
    honest_confidence: float = 0.80,
    byzantine_confidence: float = 0.95,
) -> list[MockAgent]:
    agents = []
    for i in range(n):
        is_byz = i >= (n - byzantine_count)
        agents.append(
            MockAgent(
                agent_id=f"a{i+1}",
                answer="correct" if not is_byz else f"byz-{i}",
                confidence=honest_confidence if not is_byz else byzantine_confidence,
                byzantine=is_byz,
